const body = $json.body || {};
return [{ json: {
  titulo:     body.titulo     || 'Não informado',
  problema:   body.problema   || body.descricao || 'Não informado',
  descricao:  body.descricao  || '',
  user:       body.user       || '',
  parecer_id: body.parecer_id || ''
}}];

// =======================================================
// SUPER PARSER UNIVERSAL — Camada 1: Extração multi-caminho
// Compatível com: Anthropic, OpenAI, OpenRouter, Llama, Mistral
// =======================================================
var wb = $('Normalizar Input').first().json;
var r = $input.first().json;
var txt = '';
if (typeof r.text === 'string' && r.text.trim()) { txt = r.text; }
else if (typeof r.output === 'string' && r.output.trim()) { txt = r.output; }
else if (r.message && typeof r.message.content === 'string') { txt = r.message.content; }
else if (r.choices && r.choices[0] && r.choices[0].message) { txt = '' + r.choices[0].message.content; }
else if (Array.isArray(r.content) && r.content[0]) { txt = r.content[0].text || ''; }
else if (typeof r.content === 'string') { txt = r.content; }
else { txt = JSON.stringify(r); }

// QT = char 34 = " | AP = char 39 = '
var QT = String.fromCharCode(34);
var AP = String.fromCharCode(39);

// Camada 2: Sanitização — remove trailing commas (loop, sem regex)
function removeTrailingCommas(str) {
  var out = '';
  for (var i = 0; i < str.length; i++) {
    if (str[i] === ',') {
      var j = i + 1;
      while (j < str.length && str.charCodeAt(j) <= 32) j++;
      if (j < str.length && (str[j] === '}' || str[j] === ']')) continue;
    }
    out += str[i];
  }
  return out;
}

// Sanitização — remove blocos de markdown (sem regex)
function cleanText(raw) {
  var s = raw;
  var BT = String.fromCharCode(96);
  var triple = BT + BT + BT;
  var a, b;
  while ((a = s.indexOf(triple)) >= 0) {
    b = s.indexOf(triple, a + 3);
    s = b >= 0 ? s.slice(0, a) + s.slice(b + 3) : s.slice(0, a) + s.slice(a + 3);
  }
  return removeTrailingCommas(s).trim();
}

// Camada 3: Parse com 3 tentativas de fallback
var q = null;
var cleaned = cleanText(txt);
try { q = JSON.parse(cleaned); } catch(e1) { q = null; }

if (!q) {
  var sa = cleaned.indexOf('{'), ea = cleaned.lastIndexOf('}');
  if (sa >= 0 && ea > sa) {
    try { q = JSON.parse(cleaned.slice(sa, ea + 1)); } catch(e2) { q = null; }
  }
}

if (!q) {
  var sb = txt.indexOf('{'), eb = txt.lastIndexOf('}');
  if (sb >= 0 && eb > sb) {
    try { q = JSON.parse(cleanText(txt.slice(sb, eb + 1))); } catch(e3) { q = null; }
  }
}

// Camada 4: Extração heurística por indexação manual (sem regex)
var pMode = q ? 'json' : 'heuristic';
if (!q) {
  q = { domain: '', query_ilike: '', termos: [], confidence: 0.3 };

  var k1 = QT + 'query_ilike' + QT, i1 = txt.indexOf(k1);
  if (i1 >= 0) {
    var c1 = txt.indexOf(':', i1 + k1.length);
    var p1 = txt.indexOf(QT, c1 + 1), p2 = txt.indexOf(QT, p1 + 1);
    if (p1 >= 0 && p2 > p1) q.query_ilike = txt.slice(p1 + 1, p2);
  }

  var k2 = QT + 'termos' + QT, i2 = txt.indexOf(k2);
  if (i2 >= 0) {
    var c2 = txt.indexOf('[', i2 + k2.length);
    var p3 = txt.indexOf(']', c2 + 1);
    if (c2 >= 0 && p3 > c2) {
      q.termos = txt.slice(c2 + 1, p3)
        .split(',')
        .map(function(t) { return t.split(QT).join('').trim(); })
        .filter(function(t) { return t.length > 1; });
    }
  }

  var k3 = QT + 'domain' + QT, i3 = txt.indexOf(k3);
  if (i3 >= 0) {
    var c3 = txt.indexOf(':', i3 + k3.length);
    var p5 = txt.indexOf(QT, c3 + 1), p6 = txt.indexOf(QT, p5 + 1);
    if (p5 >= 0 && p6 > p5) q.domain = txt.slice(p5 + 1, p6);
  }
}

// Limpeza final e geração do fallback de query
var qi = (q.query_ilike || '').split(QT).join('').split(AP).join('').trim();
if (!qi || qi.length < 3) {
  qi = (Array.isArray(q.termos) && q.termos.length > 0)
    ? q.termos.slice(0, 3).join(' OR ')
    : 'licitacao OR dispensa OR inexigibilidade';
  pMode += '+fallback';
}

return [{ json: {
  query_ilike:  qi,
  termos:       Array.isArray(q.termos) ? q.termos : [],
  confidence:   typeof q.confidence === 'number' ? q.confidence : 0.5,
  domain:       q.domain || '',
  _parser_mode: pMode,
  titulo:       wb.titulo,
  problema:     wb.problema,
  descricao:    wb.descricao,
  user:         wb.user,
  parecer_id:   wb.parecer_id
}}];

var resultados = $input.all();
var qn = $('Formatar Query').first().json;
var docs = [];
if (resultados && resultados.length > 0) {
  if (resultados.length === 1 && Array.isArray(resultados[0].json)) {
    docs = resultados[0].json;
  } else {
    docs = resultados.map(item => item.json).filter(doc => Object.keys(doc).length > 0);
  }
}

function stripHtml(html) {
   if (!html) return '';
   return html.replace(/<[^>]*>?/gm, ' ').replace(/\s+/g, ' ').trim();
}

var contexto = docs.slice(0, 10).map(function(doc, i) {
  var numStr = stripHtml(doc.numero || 'S/N');
  if (numStr.length > 100) { numStr = numStr.substring(0, 80) + '...'; }
  var ementaLimpa = stripHtml(doc.ementa || 'Sem ementa');
  var trecho = stripHtml(doc.snippet || '');
  var res = '[' + (i+1) + '] Acórdão/Decisão ' + numStr + ' — ' + (doc.orgao||'') + ' (' + (doc.ano||doc.data_pub||'s/d') + ')\n';
  res += 'Ementa: ' + ementaLimpa + '\n';
  if (trecho) { res += 'Trecho relevante do Inteiro Teor: [...] ' + trecho + ' [...]'; }
  return res;
}).join('\n\n---\n\n');

return [{ json: {
  problema:                qn.problema,
  titulo:                  qn.titulo,
  descricao:               qn.descricao,
  user:                    qn.user,
  parecer_id:              qn.parecer_id,
  termos_buscados:         qn.termos,
  total_encontrado:        docs.length,
  contexto_jurisprudencia: contexto
}}];

var r = $input.first().json;
var parecer = r.text || r.output || (r.content && r.content[0] && r.content[0].text) || JSON.stringify(r);
return [{ json: { output: parecer } }];
